const people = items[0].json.data;

const textOutput = people.map(person =>
  `Name: ${person["First Name"]} ${person["Last Name"]}\n` + 
  `Email: ${person["Email"]}\n` + 
  `Budget: ${person["Budget "]}\n` + 
  `Message: ${person["Message"]}`
).join("\n\n");

return [{ json: { text: textOutput }}];
